// MARK: - Secure Storage Manager

final class SecureStorageManager {
    
    static let shared = SecureStorageManager()
    
    private let encryptionManager = SecureEncryptionManager.shared
    private let fileManager = FileManager.default
    
    private var secureDirectory: URL {
        let documentsPath = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        let securePath = documentsPath.appendingPathComponent(".secure_storage", isDirectory: true)
        if !fileManager.fileExists(atPath: securePath.path) {
            try? fileManager.createDirectory(at: securePath, withIntermediateDirectories: true)
        }
        return securePath
    }
    
    private init() {}
    
    func saveEncrypted<T: Codable>(_ object: T, forKey key: String) throws {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(object)
        let encryptedData = try encryptionManager.encrypt(data: data)
        
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashSensitiveData(key))
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func loadEncrypted<T: Codable>(forKey key: String, as type: T.Type) throws -> T {
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashSensitiveData(key))
        let encryptedData = try Data(contentsOf: fileURL)
        let decryptedData = try encryptionManager.decrypt(data: encryptedData)
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: decryptedData)
    }
    
    func deleteEncrypted(forKey key: String) throws {
        let fileURL = secureDirectory.appendingPathComponent(encryptionManager.hashSensitiveData(key))
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let storageManager = SecureStorageManager.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    private let biometricAuth = BiometricAuthManager.shared
    
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactions", qos: .userInitiated)
    private let transactionLock = NSLock()
    
    private let maxTransactionAmount: Decimal = 50000.00
    private let dailyTransactionLimit: Decimal = 100000.00
    
    private init() {}
    
    // MARK: - High-Risk Operation: Process Transaction
    
    func processTransaction(
        request: TransactionRequest,
        completion: @escaping (Result<Transaction, TransactionError>) -> Void
    ) {
        // Step 1: Device integrity check before any financial operation
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        
        if integrityResult.riskLevel >= .high {
            completion(.failure(.deviceCompromised(reasons: integrityResult.reasons)))
            logSecurityEvent(event: "transaction_blocked_compromised_device", details: integrityResult.reasons.joined(separator: ", "))
            return
        }
        
        if integrityResult.riskLevel >= .medium {
            logSecurityEvent(event: "transaction_warning_suspicious_device", details: integrityResult.reasons.joined(separator: ", "))
            // Allow with additional logging and reduced limits for medium risk
        }
        
        // Step 2: Validate transaction parameters
        guard let validationResult = validateTransaction(request: request, riskLevel: integrityResult.riskLevel) else {
            completion(.failure(.validationFailed))
            return
        }
        
        guard validationResult else {
            completion(.failure(.validationFailed))
            return
        }
        
        // Step 3: Require biometric authentication for transactions
        biometricAuth.authenticateUser(reason: "Authenticate to process transaction of \(request.amount) \(request.currency)") { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success:
                self.executeTransaction(request: request, completion: completion)
            case .failure(let error):
                completion(.failure(.authenticationFailed(error.localizedDescription)))
            }
        }
    }
    
    private func validateTransaction(request: TransactionRequest, riskLevel: DeviceIntegrityChecker.IntegrityResult.RiskLevel) -> Bool? {
        // Reduced limits on suspicious devices
        let effectiveMaxAmount: Decimal
        let effectiveDailyLimit: Decimal
        
        switch riskLevel {
        case .none:
            effectiveMaxAmount = maxTransactionAmount
            effectiveDailyLimit = dailyTransactionLimit
        case .low:
            effectiveMaxAmount = maxTransactionAmount * 0.5
            effectiveDailyLimit = dailyTransactionLimit * 0.5
        case .medium:
            effectiveMaxAmount = maxTransactionAmount * 0.25
            effectiveDailyLimit = dailyTransactionLimit * 0.25
        case .high, .critical:
            return false
        }
        
        guard request.amount > 0 else { return false }
        guard request.amount <= effectiveMaxAmount else { return false }
        guard !request.fromAccountId.isEmpty else { return false }
        guard !request.currency.isEmpty else { return false }
        
        // Check daily limit
        if let dailyTotal = getDailyTransactionTotal(accountId: request.fromAccountId) {
            guard dailyTotal + request.amount <= effectiveDailyLimit else { return false }
        }
        
        return true
    }
    
    private func executeTransaction(
        request: TransactionRequest,
        completion: @escaping (Result<Transaction, TransactionError>) -> Void
    ) {
        transactionQueue.async { [weak self] in
            guard let self = self else { return }
            
            self.transactionLock.lock()
            defer { self.transactionLock.unlock() }
            
            // Re-check integrity right before execution (TOCTOU defense)
            let recheck = self.integrityChecker.performFullIntegrityCheck()
            if recheck.riskLevel >= .high {
                DispatchQueue.main.async {
                    completion(.failure(.deviceCompromised(reasons: recheck.reasons)))
                }
                return
            }
            
            do {
                var account: Account = try self.storageManager.loadEncrypted(
                    forKey: "account_\(request.fromAccountId)",
                    as: Account.self
                )
                
                guard account.balance >= request.amount || request.type == .deposit else {
                    DispatchQueue.main.async {
                        completion(.failure(.insufficientFunds))
                    }
                    return
                }
                
                let transaction = Transaction(
                    id: UUID().uuidString,
                    fromAccountId: request.fromAccountId,
                    toAccountId: request.toAccountId,
                    amount: request.amount,
                    currency: request.currency,
                    type: request.type,
                    description: request.description,
                    timestamp: Date(),
                    status: .completed,
                    referenceNumber: self.generateReferenceNumber(),
                    )
                
                switch request.type {
                case .deposit:
                    account.balance += request.amount
                case .withdrawal, .payment:
                    account.balance -= request.amount
                case .transfer:
                    account.balance -= request.amount
                    if let toAccountId = request.toAccountId {
                        self.creditAccount(accountId: toAccountId, amount: request.amount)
                    }
                }
                
                try self.storageManager.saveEncrypted(account, forKey: "account_\(account.id)")
                try self.saveTransaction(transaction)
                
                self.logSecurityEvent(event: "transaction_completed", details: "ref: \(transaction.referenceNumber), amount: \(request.amount)")
                
                DispatchQueue.main.async {
                    completion(.success(transaction))
                }
                
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.processingFailed(error.localizedDescription)))
                }
            }
        }
    }
    
    private func creditAccount(accountId: String, amount: Decimal) {
        do {
            var account: Account = try storageManager.loadEncrypted(
                forKey: "account_\(accountId)",
                as: Account.self
            )
            account.balance += amount
            try storageManager.saveEncrypted(account, forKey: "account_\(account.id)")
        } catch {
            logSecurityEvent(event: "credit_account_failed", details: "accountId: \(accountId), error: \(error.localizedDescription)")
        }
    }
    
    private func saveTransaction(_ transaction: Transaction) throws {
        var transactions: [Transaction]
        do {
            transactions = try storageManager.loadEncrypted(
                forKey: "transactions_\(transaction.fromAccountId)",
                as: [Transaction].self
            )
        } catch {
            transactions = []
        }
        transactions.append(transaction)
        try storageManager.saveEncrypted(transactions, forKey: "transactions_\(transaction.fromAccountId)")
    }
    
    private func getDailyTransactionTotal(accountId: String) -> Decimal? {
        do {
            let transactions: [Transaction] = try storageManager.loadEncrypted(
                forKey: "transactions_\(accountId)",
                as: [Transaction].self
            )
            
            let calendar = Calendar.current
            let today = calendar.startOfDay(for: Date())
            
            let dailyTotal = transactions
                .filter { calendar.startOfDay(for: $0.timestamp) == today }
                .filter { $0.status == .completed }
                .reduce(Decimal.zero) { $0 + $1.amount }
            
            return dailyTotal
        } catch {
            return Decimal.zero
        }
    }
    
    private func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 100000...999999)
        return "TXN-\(timestamp)-\(random)"
    }
    
    private func logSecurityEvent(event: String, details: String) {
        let logEntry: [String: Any] = [
            "event": event,
            "details": details,
            "timestamp": ISO8601DateFormatter().string(from: Date()),
            "device_id": UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        ]
        // In production, send to secure logging backend
        print("[SECURITY_LOG] \(logEntry)")
    }
    
    enum TransactionError: Error, LocalizedError {
        case validationFailed
        case insufficientFunds
        case authenticationFailed(String)
        case processingFailed(String)
        case dailyLimitExceeded
        case deviceCompromised(reasons: [String])
        
        var errorDescription: String? {
            switch self {
            case .validationFailed:
                return "Transaction validation failed"
            case .insufficientFunds:
                return "Insufficient funds"
            case .authenticationFailed(let reason):
                return "Authentication failed: \(reason)"
            case .processingFailed(let reason):
                return "Transaction processing failed: \(reason)"
            case .dailyLimitExceeded:
                return "Daily transaction limit exceeded"
            case .deviceCompromised(let reasons):
                return "Transaction blocked: device integrity check failed (\(reasons.joined(separator: ", ")))"
            }
        }
    }
}

// MARK: - Account Manager

final class AccountManager {
    
    static let shared = AccountManager()
    
    private let storageManager = SecureStorageManager.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    
    private init() {}
    
    func createAccount(
        accountNumber: String,
        type: Account.AccountType,
        ownerName: String,
        initialBalance: Decimal = 0,
        currency: String = "USD"
    ) throws -> Account {
        // Integrity check for account creation
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        if integrityResult.riskLevel >= .high {
            throw AccountError.deviceCompromised
        }
        
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountType: type,
            balance: initialBalance,
            currency: currency,
            ownerName: ownerName,
            createdAt: Date()
        )
        
        try storageManager.saveEncrypted(account, forKey: "account_\(account.id)")
        
        var accountIds: [String]
        do {
            accountIds = try storageManager.loadEncrypted(forKey: "account_ids", as: [String].self)
        } catch {
            accountIds = []
        }
        accountIds.append(account.id)
        try storageManager.saveEncrypted(accountIds, forKey: "account_ids")
        
        return account
    }
    
    func getAccount(id: String) throws -> Account {
        return try storageManager.loadEncrypted(forKey: "account_\(id)", as: Account.self)
    }
    
