        let accountIds: [String]
        do {
            accountIds = try storageManager.loadEncrypted(forKey: "account_ids", as: [String].self)
        } catch {
            return []
        }
        
        return accountIds.compactMap { id in
            try? storageManager.loadEncrypted(forKey: "account_\(id)", as: Account.self)
        }
    }
    
