            throw AccountError.deviceCompromised
        }
        
        do {
            return try storageManager.loadEncrypted(
                forKey: "transactions_\(accountId)",
                as: [Transaction].self
            )
        } catch {
            return []
        }
    }
    
    func getMaskedAccountNumber(_ accountNumber: String) -> String {
        guard accountNumber.count > 4 else { return accountNumber }
        let lastFour = String(accountNumber.suffix(4))
        let masked = String(repeating: "•", count: accountNumber.count - 4)
        return masked + lastFour
    }
    
    enum AccountError: Error, LocalizedError {
        case accountNotFound
        case deviceCompromised
        case storageFailed
        
        var errorDescription: String? {
            switch self {
            case .accountNotFound: return "Account not found"
            case .deviceCompromised: return "Operation blocked due to device integrity concerns"
            case .storageFailed: return "Failed to store account data"
            }
        }
    }
}

// MARK: - SSL Pinning Configuration

final class SSLPinningManager {
    
    static let shared = SSLPinningManager()
    
    // SHA256 hashes of expected server certificate public keys
    private let pinnedCertificateHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=",  // Primary
        "CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="   // Backup
    ]
    
    private init() {}
    
    func createPinnedURLSession() -> URLSession {
        let configuration = URLSessionConfiguration.ephemeral
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        configuration.urlCache = nil
        configuration.requestCachePolicy = .reloadIgnoringLocalCacheData
        
        let delegate = SSLPinningDelegate(pinnedHashes: pinnedCertificateHashes)
        return URLSession(configuration: configuration, delegate: delegate, delegateQueue: nil)
    }
}

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedHashes: Set<String>
    
    init(pinnedHashes: Set<String>) {
        self.pinnedHashes = pinnedHashes
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let policies = [SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)]
        SecTrustSetPolicies(serverTrust, policies as CFTypeRef)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var foundMatch = false
        
        for index in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, index) else { continue }
            
            let certData = SecCertificateCopyData(certificate) as Data
            let hash = SHA256.hash(data: certData)
            let hashString = Data(hash).base64EncodedString()
            
            if pinnedHashes.contains(hashString) {
                foundMatch = true
                break
            }
        }
        
        if foundMatch {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Anti-Tampering Manager

final class AntiTamperingManager {
    
    static let shared = AntiTamperingManager()
    
    private init() {}
    
    func verifyAppIntegrity() -> Bool {
        return verifyBundleSignature() && verifyExecutableIntegrity()
    }
    
    private func verifyBundleSignature() -> Bool {
        guard let bundlePath = Bundle.main.bundlePath as NSString? else { return false }
        
        let embeddedProvisionPath = bundlePath.appendingPathComponent("embedded.mobileprovision")
        
        #if targetEnvironment(simulator)
        return true
        #else
        return FileManager.default.fileExists(atPath: embeddedProvisionPath)
        #endif
    }
    
    private func verifyExecutableIntegrity() -> Bool {
        guard let executablePath = Bundle.main.executablePath else { return false }
        return FileManager.default.fileExists(atPath: executablePath)
    }
    
    func setupRuntimeProtections() {
        // Disable pasteboard for sensitive fields
        disableThirdPartyKeyboards()
        
        // Prevent screen capture of sensitive content
        setupScreenCaptureProtection()
    }
    
    private func disableThirdPartyKeyboards() {
        // Override in AppDelegate to restrict keyboard extensions
    }
    
    private func setupScreenCaptureProtection() {
        NotificationCenter.default.addObserver(
            forName: UIApplication.userDidTakeScreenshotNotification,
            object: nil,
            queue: .main
        ) { _ in
            // Log security event
            print("[SECURITY_LOG] Screenshot detected on banking screen")
        }
    }
}

// MARK: - Secure Session Manager

final class SecureSessionManager {
    
    static let shared = SecureSessionManager()
    
    private var sessionToken: String?
    private var sessionExpiry: Date?
    private let sessionTimeout: TimeInterval = 300 // 5 minutes
    private var lastActivityTime: Date?
    private let integrityChecker = DeviceIntegrityChecker.shared
    
    private init() {}
    
    func startSession(token: String) {
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        
        if integrityResult.riskLevel >= .high {
            invalidateSession()
            return
        }
        
        sessionToken = token
        sessionExpiry = Date().addingTimeInterval(sessionTimeout)
        lastActivityTime = Date()
    }
    
    func isSessionValid() -> Bool {
        guard let expiry = sessionExpiry, let _ = sessionToken else {
            return false
        }
        
        // Re-check integrity periodically
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        if integrityResult.riskLevel >= .high {
            invalidateSession()
            return false
        }
        
        if Date() > expiry {
            invalidateSession()
            return false
        }
        
        // Check inactivity timeout
        if let lastActivity = lastActivityTime,
           Date().timeIntervalSince(lastActivity) > sessionTimeout {
            invalidateSession()
            return false
        }
        
        return true
    }
    
    func refreshActivity() {
        lastActivityTime = Date()
        sessionExpiry = Date().addingTimeInterval(sessionTimeout)
    }
    
    func invalidateSession() {
        sessionToken = nil
        sessionExpiry = nil
        lastActivityTime = nil
    }
    
    func getSessionToken() -> String? {
        guard isSessionValid() else { return nil }
        return sessionToken
    }
}

// MARK: - Banking View Controller

final class BankingViewController: UIViewController {
    
    private let accountManager = AccountManager.shared
    private let transactionProcessor = TransactionProcessor.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    private let antiTampering = AntiTamperingManager.shared
    private let sessionManager = SecureSessionManager.shared
    
    private var accounts: [Account] = []
    
    private lazy var secureContentView: UIView = {
        let view = UIView()
        view.translatesAutoresizingMaskIntoConstraints = false
        return view
    }()
    
    private lazy var tableView: UITableView = {
        let table = UITableView(frame: .zero, style: .insetGrouped)
        table.translatesAutoresizingMaskIntoConstraints = false
        table.delegate = self
        table.dataSource = self
        table.register(AccountCell.self, forCellReuseIdentifier: AccountCell.reuseIdentifier)
        return table
    }()
    
    private lazy var securityBanner: UIView = {
        let view = UIView()
        view.translatesAutoresizingMaskIntoConstraints = false
        view.backgroundColor = .systemRed
        view.isHidden = true
        
        let label = UILabel()
        label.translatesAutoresizingMaskIntoConstraints = false
        label.text = "⚠️ Security Warning: Device integrity compromised. Some features are restricted."
        label.textColor = .white
        label.font = .systemFont(ofSize: 12, weight: .semibold)
        label.numberOfLines = 0
        label.textAlignment = .center
        
        view.addSubview(label)
        NSLayoutConstraint.activate([
            label.topAnchor.constraint(equalTo: view.topAnchor, constant: 8),
            label.bottomAnchor.constraint(equalTo: view.bottomAnchor, constant: -8),
            label.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            label.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])
        
        return view
    }()
    
    private var screenProtectionView: UIView?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        setupUI()
        performStartupSecurityChecks()
        setupScreenProtection()
        antiTampering.setupRuntimeProtections()
        loadAccounts()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        
        // Check session validity
        if !sessionManager.isSessionValid() {
            promptReauthentication()
            return
        }
        
        sessionManager.refreshActivity()
    }
    
    private func setupUI() {
        title = "Accounts"
        view.backgroundColor = .systemBackground
        
        view.addSubview(securityBanner)
        view.addSubview(secureContentView)
        secureContentView.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            securityBanner.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            securityBanner.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            securityBanner.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            
            secureContentView.topAnchor.constraint(equalTo: securityBanner.bottomAnchor),
            secureContentView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            secureContentView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            secureContentView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            tableView.topAnchor.constraint(equalTo: secureContentView.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: secureContentView.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: secureContentView.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: secureContentView.bottomAnchor)
        ])
        
        let transferButton = UIBarButtonItem(
            title: "Transfer",
            style: .plain,
            target: self,
            action: #selector(initiateTransfer)
        )
        navigationItem.rightBarButtonItem = transferButton
    }
    
    private func setupScreenProtection() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(applicationWillResignActive),
            name: UIApplication.willResignActiveNotification,
            object: nil
        )
        
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(applicationDidBecomeActive),
            name: UIApplication.didBecomeActiveNotification,
            object: nil
        )
    }
    
    @objc private func applicationWillResignActive() {
        // Hide sensitive content when app goes to background
        let protectionView = UIView(frame: view.bounds)
        protectionView.backgroundColor = .systemBackground
        protectionView.tag = 999
        
        let logoLabel = UILabel()
        logoLabel.text = "🏦 Secure Banking"
        logoLabel.font = .systemFont(ofSize: 24, weight: .bold)
        logoLabel.textAlignment = .center
        logoLabel.translatesAutoresizingMaskIntoConstraints = false
        
        protectionView.addSubview(logoLabel)
        NSLayoutConstraint.activate([
            logoLabel.centerXAnchor.constraint(equalTo: protectionView.centerXAnchor),
            logoLabel.centerYAnchor.constraint(equalTo: protectionView.centerYAnchor)
        ])
        
        view.addSubview(protectionView)
        screenProtectionView = protectionView
    }
    
    @objc private func applicationDidBecomeActive() {
        screenProtectionView?.removeFromSuperview()
        screenProtectionView = nil
        
        // Re-validate session on return
        if !sessionManager.isSessionValid() {
            promptReauthentication()
        }
    }
    
    private func performStartupSecurityChecks() {
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        
        if integrityResult.riskLevel >= .critical {
            showCriticalSecurityAlert()
            return
        }
        
        if integrityResult.isCompromised {
            securityBanner.isHidden = false
        }
        
        if !antiTampering.verifyAppIntegrity() {
            showTamperingAlert()
        }
    }
    
    private func showCriticalSecurityAlert() {
        let alert = UIAlertController(
            title: "Security Alert",
            message: "This device has been identified as compromised. For your security, banking operations are not available on this device. Please use a secure device.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .destructive) { [weak self] _ in
            self?.secureContentView.isHidden = true
            self?.navigationItem.rightBarButtonItem?.isEnabled = false
        })
        present(alert, animated: true)
    }
    
    private func showTamperingAlert() {
        let alert = UIAlertController(
            title: "Security Warning",
            message: "App integrity could not be verified. Please reinstall the app from the App Store.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func promptReauthentication() {
        BiometricAuthManager.shared.authenticateUser(reason: "Re-authenticate to continue") { [weak self] result in
            switch result {
            case .success:
                self?.sessionManager.startSession(token: UUID().uuidString)
            case .failure:
                let alert = UIAlertController(
                    title: "Session Expired",
                    message: "Please log in again to continue.",
                    preferredStyle: .alert
                )
                alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
                    // Navigate to login screen
                })
                self?.present(alert, animated: true)
            }
        }
    }
    
    private func loadAccounts() {
        do {
            accounts = try accountManager.getAllAccounts()
            
            if accounts.isEmpty {
                // Create demo accounts for testing
                let checking = try accountManager.createAccount(
                    accountNumber: "1234567890",
                    type: .checking,
                    ownerName: "John Doe",
                    initialBalance: 5432.10,
                    currency: "USD"
                )
                let savings = try accountManager.createAccount(
                    accountNumber: "0987654321",
                    type: .savings,
                    ownerName: "John Doe",
                    initialBalance: 25000.00,
                    currency: "USD"
                )
                accounts = [checking, savings]
            }
            
            tableView.reloadData()
        } catch {
            showError(error)
        }
    }
    
    @objc private func initiateTransfer() {
        // Integrity check before showing transfer UI
        let integrityResult = integrityChecker.performFullIntegrityCheck()
        if integrityResult.riskLevel >= .high {
            showCriticalSecurityAlert()
            return
        }
        
        guard let fromAccount = accounts.first else { return }
        
        let alert = UIAlertController(title: "Transfer Funds", message: "Enter amount to transfer", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
            // Disable third-party keyboard for sensitive input
            textField.isSecureTextEntry = false
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Transfer", style: .default) { [weak self] _ in
            guard let amountText = alert.textFields?.first?.text,
                  let amount = Decimal(string: amountText) else {
                return
            }
            
            let request = TransactionRequest(
                fromAccountId: fromAccount.id,
                toAccountId: self?.accounts.last?.id,
                amount: amount,
                currency: "USD",
                type: .transfer,
                description: "Internal transfer"
            )
            
            self?.transactionProcessor.processTransaction(request: request) { result in
                switch result {
                case .success(let transaction):
                    self?.showSuccess(message: "Transfer successful!\nRef: \(transaction.referenceNumber)")
                    self?.loadAccounts()
                case .failure(let error):
                    self?.showError(error)
                }
            }
        })
        
        present(alert, animated: true)
    }
    
    private func showError(_ error: Error) {
        let alert = UIAlertController(
            title: "Error",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSuccess(message: String) {
        let alert = UIAlertController(
            title: "Success",
            message: message,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - UITableView DataSource & Delegate

extension BankingViewController: UITableViewDataSource, UITableViewDelegate {
    
    func numberOfSections(in tableView: UITableView) -> Int {
        return 1
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return accounts.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        guard let cell = tableView.dequeueReusableCell(withIdentifier: AccountCell.reuseIdentifier, for: indexPath) as? AccountCell else {
            return UITableViewCell()
        }
        
        let account = accounts[indexPath.row]
        cell.configure(with: account, maskedNumber: accountManager.getMaskedAccountNumber(account.accountNumber))
        return cell
    }
    
    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        return "Your Accounts"
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        sessionManager.refreshActivity()
        
        let account = accounts[indexPath.row]
        showAccountDetails(account)
    }
    
    private func showAccountDetails(_ account: Account) {
        do {
            let transactions = try accountManager.getTransactionHistory(accountId: account.id)
            
            let detailVC = AccountDetailViewController(account: account, transactions: transactions)
            navigationController?.pushViewController(detailVC, animated: true)
        } catch {
            showError(error)
        }
    }
}

